import React, { useEffect } from "react";
import ReactDOM from "react-dom";
import { CSSTransition } from "react-transition-group";
import "./Modal.css";

const Modal = (props) => {
  const closeOnEscapeKeyDown = (e) => {
    if ((e.charCode || e.keyCode) === 27) {
      props.onClose();
    }
  };

  useEffect(() => {
    document.body.addEventListener("keydown", closeOnEscapeKeyDown);
    return function cleanup() {
      document.body.removeEventListener("keydown", closeOnEscapeKeyDown);
    };
  }, []);

  return ReactDOM.createPortal(
    <CSSTransition in={props.show} unmountOnExit timeout={{ enter: 0, exit: 300 }}>
      <div className="modal" onClick={props.onClose}>
        <div className="modal-content" onClick={(e) => e.stopPropagation()}>
          <div className="modal-header">
            <h4 className="modal-title">{props.title}</h4>
          </div>
          <div className="modal-body">{props.children}
          Ankit
          <div className="card text-center" style={{marginTop: '3%', marginLeft : '27%', marginRight : '10%', width:'50%'}}>
            <div className="card-body">
            <h5 className="card-title">Register for host</h5>
            <form>
                {/* Name input */}
                <div className="form-outline mb-4">
                <span style={{float: 'left'}}>
                    <input type="email" id="form2Example1" className="form-control" disabled defaultValue="Tathtya" />
                    First Name
                    {/* <label className="form-label" htmlFor="form2Example1">First Name</label> */}
                </span>
                <span style={{float: 'right'}}>
                    <input type="email" id="form2Example1" className="form-control" disabled defaultValue="Patel" />
                    Last Name
                    {/* <label className="form-label" htmlFor="form2Example1">Last Name</label> */}
                </span>
                </div>

                {/* Email input */}
                <div className="form-outline mb-4">
                    <input type="email" id="form2Example1" className="form-control" disabled defaultValue="tathya@mail.com" />
                    e-mail
                    {/* <label className="form-label" htmlFor="form2Example1">Email address</label> */}
                </div>

                {/* Contact, DOB input */}
                <div className="form-outline mb-4" style={{display : 'flex'}}>
                <span style={{flex : 1}}>
                    <input type="text" id="form2Example1" className="form-control" />
                    Phone no.
                    {/* <label className="form-label" htmlFor="form2Example1">Phone no.</label> */}
                </span>
                <span style={{flex : 1}}>
                    <input type="date" id="form2Example1" className="form-control" />
                    DOB
                    {/* <label className="form-label" htmlFor="form2Example1">DOB</label> */}
                </span>
                </div>

                {/* Street input */}
                <div className="form-outline mb-4">
                <input type="text" id="form2Example1" className="form-control" />
                Street
                {/* <label className="form-label" htmlFor="form2Example1">Street</label> */}
                </div>

                {/* City, State input */}
                <div className="form-outline mb-4" style={{display : 'flex'}}>
                <span style={{flex : 1}}>
                    <input type="text" id="form2Example1" className="form-control" />
                    City
                    {/* <label className="form-label" htmlFor="form2Example1">City</label> */}
                </span>
                <span style={{flex : 1}}>
                    <input type="text" id="form2Example1" className="form-control" />
                    State
                    {/* <label className="form-label" htmlFor="form2Example1">State</label> */}
                </span>
                <span style={{flex : 1}}>
                    <input type="text" id="form2Example1" className="form-control" />
                    Zip Code
                    {/* <label className="form-label" htmlFor="form2Example1">Zip Code</label> */}
                </span>
                </div>

                {/* Account, bank name input */}
                <div className="form-outline mb-4" style={{display : 'flex'}}>
                <span style={{flex : 1}}>
                    <input type="text" id="form2Example1" className="form-control" />
                    Account Name
                    {/* <label className="form-label" htmlFor="form2Example1">Account Name</label> */}
                </span>
                <span style={{flex : 1}}>
                    <input type="text" id="form2Example1" className="form-control" />
                    Bank Name
                    {/* <label className="form-label" htmlFor="form2Example1">Bank Name</label> */}
                </span>
                </div>

                {/* Account, routing name input */}
                <div className="form-outline mb-4" style={{display : 'flex'}}>
                <span style={{flex : 1}}>
                    <input type="text" id="form2Example1" className="form-control" />
                    Account Number
                    {/* <label className="form-label" htmlFor="form2Example1">Account Number</label> */}
                </span>
                <span style={{flex : 1}}>
                    <input type="text" id="form2Example1" className="form-control" />
                    Routing Number
                    {/* <label className="form-label" htmlFor="form2Example1">Routing Number</label> */}
                </span>
                </div>

                {/* Password input */}
                <div className="form-outline mb-4">
                    <input type="password" id="form2Example2" className="form-control" />
                    {/* <label className="form-label" htmlFor="form2Example2">Confirm Password</label> */}
                </div>

                {/* Submit button */}
                <button type="button" className="btn btn-primary btn-block mb-4">Register</button>

            </form>
            </div>
      </div>
          </div>
          <div className="modal-footer">
            <button onClick={props.onClose} className="button">
              Close
            </button>
          </div>
        </div>
      </div>
    </CSSTransition>,
    document.getElementById("root")
  );
};

export default Modal;
